#:property AllowUnsafeBlocks=true

Console.WriteLine("=== stackalloc Span<nint> / Span<nuint> test ===");

// stackalloc nint (signed native-sized integer)
Span<nint> signed = stackalloc nint[4];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.WriteLine($"Span<nint> length: {signed.Length}, sizeof(nint): {sizeof(nint)}");
for (int i = 0; i < signed.Length; i++)
    Console.WriteLine($"  signed[{i}] = {signed[i]}");

// stackalloc nuint (unsigned native-sized integer)
Span<nuint> unsigned = stackalloc nuint[4];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine($"Span<nuint> length: {unsigned.Length}, sizeof(nuint): {sizeof(nuint)}");
for (int i = 0; i < unsigned.Length; i++)
    Console.WriteLine($"  unsigned[{i}] = {unsigned[i]}");

Console.WriteLine("\nAll done — stackalloc Span<nint> and Span<nuint> work!");

